using System.Diagnostics;
using System.Runtime.CompilerServices;
using System.Runtime.InteropServices;
using TextAnalysis;

// --- Setup ---
var rng = new Random(42);
var words = new string[10_000];
for (int i = 0; i < words.Length; i++)
{
    int len = rng.Next(1, 15);
    var chars = new char[len];
    for (int j = 0; j < len; j++)
        chars[j] = (char)('a' + rng.Next(0, 26));
    words[i] = new string(chars);
}
var analyzer = new TextAnalyzer(string.Join(' ', words));

// --- Benchmark helpers ---
const int WarmupIterations = 500;
const int MeasuredIterations = 10_000;

static double BenchmarkNs(Action action)
{
    // Warmup
    for (int i = 0; i < WarmupIterations; i++) action();

    // Measured
    var sw = Stopwatch.StartNew();
    for (int i = 0; i < MeasuredIterations; i++) action();
    sw.Stop();
    return (double)sw.Elapsed.TotalNanoseconds / MeasuredIterations;
}

// --- Run ---
string runtime = RuntimeInformation.FrameworkDescription;
Console.WriteLine($"Runtime: {runtime}");
Console.WriteLine($"Warmup: {WarmupIterations} iterations | Measured: {MeasuredIterations} iterations");
Console.WriteLine();

var results = new (string Name, double NsPerOp)[]
{
    ("AverageWordLength",  BenchmarkNs(() => analyzer.AverageWordLength())),
    ("WordLengthHistogram", BenchmarkNs(() => analyzer.WordLengthHistogram())),
    ("UniqueWordCount",    BenchmarkNs(() => analyzer.UniqueWordCount())),
};

Console.WriteLine($"{"Method",-25} {"ns/op",12}");
Console.WriteLine(new string('-', 38));
foreach (var (name, ns) in results)
    Console.WriteLine($"{name,-25} {ns,12:F1}");

